// === DSCR CALCULATION (JavaScript — not the LLM) ===
function calcDSCR(ebitda, ads, facility, rate, tenor, repType) {
  const r = { dscr_base: null, assessment: null, ads_used: null, notes: [] };
  if (!ebitda) { r.notes.push('EBITDA not available — DSCR cannot be calculated'); return r; }
  if (!ads) {
    if (facility && rate && tenor) {
      const interest = facility * (rate / 100);
      ads = (repType === 'bullet') ? interest : interest + (facility / tenor);
      r.notes.push(repType === 'bullet' ? 'Bullet: ADS = interest only' : 'Amortising: ADS = interest + principal');
    } else {
      r.notes.push('Cannot estimate ADS — missing facility amount, rate, or tenor'); return r;
    }
  }
  r.ads_used = Math.round(ads);
  const d = ebitda / ads;
  r.dscr_base = Math.round(d * 100) / 100;
  if (d >= 1.50) r.assessment = 'STRONG — significant headroom above 1.50x';
  else if (d >= 1.25) r.assessment = 'ADEQUATE — comfortable above 1.25x minimum';
  else if (d >= 1.10) r.assessment = 'MARGINAL — above 1.10x floor but limited headroom';
  else if (d >= 1.00) r.assessment = 'WEAK — above 1.0x but below acceptable minimum';
  else r.assessment = 'CRITICAL — DSCR below 1.0x, debt service not covered by cash flow';
  return r;
}

function calcWaterfall(collateral, facility) {
  const r = { ltv_calculated: null, coverage_ratio: null, assessment: null, notes: [] };
  if (!collateral || !facility) { r.notes.push('Insufficient data for LTV calculation'); return r; }
  const ltv = (facility / collateral) * 100;
  r.ltv_calculated = Math.round(ltv * 10) / 10;
  r.coverage_ratio = Math.round((collateral / facility) * 100) / 100;
  if (ltv <= 50) r.assessment = 'STRONG — LTV below 50%, substantial collateral headroom';
  else if (ltv <= 65) r.assessment = 'ADEQUATE — LTV within 65% threshold';
  else if (ltv <= 75) r.assessment = 'ACCEPTABLE — LTV within 75% limit';
  else if (ltv <= 80) r.assessment = 'ELEVATED — approaching 80% LTV ceiling';
  else r.assessment = 'HIGH — LTV exceeds 80%, collateral may be insufficient';
  return r;
}

function calcStress(baseDSCR, baseLTV) {
  const s = {};
  if (baseDSCR) {
    s.dscr_stress = {
      base: baseDSCR,
      revenue_down_10pct: Math.round(baseDSCR * 0.90 * 100) / 100,
      revenue_down_20pct: Math.round(baseDSCR * 0.80 * 100) / 100,
      revenue_down_30pct: Math.round(baseDSCR * 0.70 * 100) / 100,
      break_even_revenue_decline: baseDSCR > 0 ? (Math.round((1 - 1.10 / baseDSCR) * 1000) / 10) + '%' : 'N/A'
    };
  }
  if (baseLTV) {
    s.ltv_stress = {
      base: baseLTV,
      collateral_down_10pct: Math.round(baseLTV / 0.90 * 10) / 10,
      collateral_down_20pct: Math.round(baseLTV / 0.80 * 10) / 10
    };
  }
  if (!baseDSCR && !baseLTV) s.note = 'Insufficient base case data for stress scenarios';
  return s;
}

const dscrResult = calcDSCR(
  params.ebitda_annual, params.annual_debt_service,
  params.proposed_facility_amount, params.interest_rate_pct,
  params.tenor_years, params.repayment_type
);
const waterfallResult = calcWaterfall(params.collateral_value, params.proposed_facility_amount);
const stressResult = calcStress(dscrResult.dscr_base, waterfallResult.ltv_calculated);

const calcResults = {
  dscr_analysis: dscrResult,
  waterfall: waterfallResult,
  stress_scenarios: stressResult
};

