const flags = compResult.compliance_flags || [];
const highFlags = flags.filter(f => f.severity === 'HIGH');
const pt = prev.parsed_terms;

const TCB_TONE = 'WRITING STANDARDS — TCB CIBG CREDIT DOCUMENTS:

Voice & Tone:
- Formal professional English, appropriate for Vietnamese commercial banking
- Active voice where possible; passive only for regulatory statements
- No hedging language — say what is, or say it is unknown
- No filler openings — state the deal directly
- No AI-style sentences ("It is worth noting...", "Furthermore...", "In conclusion...")

Numbers & Data:
- All figures must cite their source inline (e.g. "USD 7.2M EBITDA, per audited FS FY2025, IFRS")
- IFRS vs VAS must be specified for all financial metrics
- Unverified data must be labelled [Estimate — verify with live data]

Regulatory References:
- Always cite full Circular/Decree title: "Circular 22/2019/TT-NHNN" not "Circular 22"
- If reference cannot be confirmed: [Regulation — verify current status with Legal]

Structure:
- Headings must be informative: "DSCR at 1.4x — Adequate Coverage" not "Financial Analysis"
- Recommendation must be unambiguous: Approve / Approve subject to conditions / Decline';

const MEMO_STRUCTURE = '1. EXECUTIVE SUMMARY — 3-4 sentences: who, what, why, key risk, recommendation
2. BORROWER BACKGROUND — corporate profile, ownership, history, financials (note IFRS/VAS)
3. TRANSACTION STRUCTURE — facility type, amount, tenor, pricing, repayment, security, purpose
4. FINANCIAL ANALYSIS — use the VERIFIED figures exactly (DSCR, LTV, stress scenarios)
5. MARKET & SECTOR CONTEXT — sector outlook, comparables, SBV policy, macro risks
6. SECURITY & COLLATERAL — description, valuation basis, LTV, enforceability under Vietnamese law
7. REGULATORY & COMPLIANCE ASSESSMENT — SBV limits, foreign currency, IFRS/VAS flags; ALL HIGH flags must appear here
8. RISK ASSESSMENT & MITIGANTS — top 5 risks with severity and mitigant
9. CONDITIONS & COVENANTS — CPs, financial covenants (specify IFRS or VAS basis), reporting requirements
