const prev = $('Parse Compliance + Build Memo Request').first().json;
const memo = ($input.first().json.choices[0].message.content || '').trim();

const borrower = prev.parsed_terms.borrower || 'Unknown Borrower';
const date = new Date().toLocaleDateString('en-GB', { day: '2-digit', month: 'long', year: 'numeric' });
const dscr = prev.calc_results?.dscr_analysis?.dscr_base;
const dscrAssess = prev.calc_results?.dscr_analysis?.assessment || '';
const ltv = prev.calc_results?.waterfall?.ltv_calculated;
const ltvAssess = prev.calc_results?.waterfall?.assessment || '';
const regPos = prev.compliance_result?.overall_regulatory_position || 'REVIEW REQUIRED';
const flagCount = (prev.compliance_flags || []).length;
const highCount = (prev.compliance_flags || []).filter(f => f.severity === 'HIGH').length;

const regColor = regPos === 'CLEAR' ? '#198754' : regPos.includes('SIGNIFICANT') ? '#dc3545' : '#fd7e14';

// Convert memo text to HTML
const htmlMemo = memo.split('\n').map(line => {
  const t = line.trim();
  if (!t) return '<br>';
  if (t.match(/^\d{1,2}\./)) return '<h3>' + t + '</h3>';
  if (t.match(/^[A-Z][A-Z\s&—:]+$/) && t.length < 80 && t.length > 3) return '<h3>' + t + '</h3>';
  if (t.startsWith('- ') || t.startsWith('• ')) return '<li>' + t.slice(2) + '</li>';
  return '<p>' + t + '</p>';
}).join('\n');

const html = `<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>CC Memo — ${borrower}</title>
