  .header{background:#002147;color:#fff;padding:20px 30px;margin-bottom:20px}
  .header h1{margin:0 0 6px 0;font-size:16px;letter-spacing:1px;font-family:Arial,sans-serif}
  .header p{margin:0;font-size:12px;opacity:.75;font-family:Arial,sans-serif}
  .metrics{display:grid;grid-template-columns:repeat(3,1fr);gap:12px;margin-bottom:20px}
