  .metric .lbl{font-size:10px;color:#666;text-transform:uppercase;letter-spacing:.5px;font-family:Arial,sans-serif}
  .metric .val{font-size:22px;font-weight:bold;color:#002147;margin:4px 0 2px;font-family:Arial,sans-serif}
  .metric .sub{font-size:11px;color:#555;font-family:Arial,sans-serif}
  .memo{background:#fff;padding:40px 48px;box-shadow:0 1px 4px rgba(0,0,0,.1)}
