  p{line-height:1.75;margin:10px 0;font-size:14px}
  li{margin:5px 0 5px 24px;font-size:14px;line-height:1.65}
  .disclaimer{margin-top:30px;padding:14px 18px;background:#fff3cd;border:1px solid #ffc107;font-size:12px;color:#7d5a00;font-family:Arial,sans-serif}
  .btn{background:#002147;color:#fff;border:none;padding:9px 18px;cursor:pointer;font-size:12px;margin-bottom:16px;font-family:Arial,sans-serif;letter-spacing:.3px}
  .btn:hover{background:#003580}
  @media print{.btn{display:none}body{background:#fff}.memo{box-shadow:none}}
</style>
</head>
